#include<bits/stdc++.h>
using namespace std;
long long a[100010],b[100010];
long long gcd(long long x,long long y)
{
    return(x%y==0?y:gcd(y,x%y));
}
int main()
{
    queue<long long> q,q1;
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        b[i]=a[i];
    }
    long long ans=0;
    for(long long r=1;r<=n;r++)
    {
        long long l1=-1;
        while(!q1.empty())
        {
            long long l=q1.front();
            q1.pop();
            b[l]=gcd(b[l],b[r]);
            ans=max(ans,b[l]*(r-l+1));
            if(l1==-1||b[l1]!=b[l])
            {
                l1=l;
                q.push(l);
            }
        }
        ans=max(ans,b[r]);
        while(!q.empty())
        {
            q1.push(q.front());
            q.pop();
        }
        if(b[l1]!=b[r])
        {
            q1.push(r);
        }
    }
    printf("%lld",ans);
    return 0;
}
